Source code in <code>src/not_again_ai/llm/chat_completion/providers/openai_api.py</code> <pre><code>def create_client_callable_stream(
    client_class: type[AsyncOpenAI | AsyncAzureOpenAI], **client_args: Any
) -&gt; Callable[..., Any]:
    filtered_args = {k: v for k, v in client_args.items() if v is not None}

    def client_callable(**kwargs: Any) -&gt; Coroutine[Any, Any, Any]:
        client = client_class(**filtered_args)
        kwargs["stream_options"] = {"include_usage": True}
        stream = client.chat.completions.create(**kwargs)
        return stream

    return client_callable
